// Normalizar la URL de imagen de cualquier proveedor
const content = $('🔧 Parsear contenido').first().json;
const imageData = $input.first().json;
const model = content.image_model;

let finalUrl = null;

if (model === 'flux' || model === 'nanoBanana') {
  // FAL.AI devuelve: { images: [{ url }] } o { image: { url } }
  finalUrl = imageData.images?.[0]?.url
          || imageData.image?.url
          || null;
} else if (model === 'ideogram') {
  // Ideogram devuelve: { data: [{ url }] }
  finalUrl = imageData.data?.[0]?.url || null;
} else if (model === 'custom') {
  finalUrl = content.image_url;
}

if (!finalUrl) {
  console.warn('⚠ No se pudo extraer URL de imagen. Respuesta:', JSON.stringify(imageData).substring(0, 300));
}

return [{ json: { ...content, final_image_url: finalUrl, image_provider_response: imageData } }];

// Handle single-post and carousel — read from correct upstream node
let d;
try {
  d = $('🗂️ Collect Image URLs').first().json;
} catch(e1) {
  try {
    d = $('🔗 Normalizar URL imagen').first().json;
  } catch(e2) {
    d = $input.first().json;
  }
}

const isCarousel = d.format === 'carousel';

const typeEmoji  = { educational:'📚', authority:'🎤', case_study:'🏆' };
const typeLabel  = { educational:'Educativo', authority:'Autoridad', case_study:'Caso de éxito' };
const modelInfo  = {
  flux:       '⚡ Flux 2 Pro',
  ideogram:   '🔤 Ideogram v3',
  nanoBanana: '🍌 Nano Banana Pro',
  custom:     '📎 Imagen propia',
};

const igPreview = d.instagram?.caption?.substring(0, 280) || 'N/A';
const fbPreview = d.facebook?.caption?.substring(0, 180) || 'N/A';
const igDots = (d.instagram?.caption?.length || 0) > 280 ? '...' : '';
const fbDots = (d.facebook?.caption?.length || 0)  > 180 ? '...' : '';

const imageStatus = isCarousel
  ? `🎠 ${d.image_urls?.length || 0} imágenes generadas (carrusel)`
  : `🖼️ ${d.final_image_url ? '✅ Imagen generada' : '⚠️ Sin imagen'}`;

const formatLine = isCarousel
  ? `\n🎠 *Formato:* Carrusel (${d.num_images} slides)`
  : '';

const msg = `🚀 *PROPULSAR CONTENT ENGINE*

${typeEmoji[d.type] || '📝'} *Tipo:* ${typeLabel[d.type] || d.type}
📌 *Tema:* ${d.topic}
${d.angle ? `🎯 *Ángulo:* ${d.angle}\n` : ''}📱 *Redes:* ${(d.platforms || []).join(', ')}
🖼️ *Imagen:* ${modelInfo[d.image_model] || d.image_model}${formatLine}

━━━━━━━━━━━━━━━━
📸 *INSTAGRAM:*
${igPreview}${igDots}

━━━━━━━━━━━━━━━━
👥 *FACEBOOK:*
${fbPreview}${fbDots}

━━━━━━━━━━━━━━━━
${imageStatus}

*¿Publicar?*
✅ *SI* para publicar
❌ *NO* para cancelar`;

return [{ json: { ...d, whatsapp_message: msg, session_id: `propulsar_${Date.now()}` } }];

// Normalize both single-post and carousel briefs into the sub-workflow's expected input shape.
// Single post: $json has final_image_url (string).
// Carousel: $json has image_urls (array of strings) and num_images.
//
// Output shape for Execute Workflow:
//   { image_urls: [{ index, url }], post_id, approval_number }

const data = $input.first().json;
const format = data.format || 'single';

let imageUrls = [];
if (format === 'carousel' && Array.isArray(data.image_urls)) {
  imageUrls = data.image_urls.map((url, i) => ({ index: i + 1, url }));
} else if (data.final_image_url) {
  imageUrls = [{ index: 1, url: data.final_image_url }];
} else {
  throw new Error('Prep Re-host Input: no image URL found on approved post (neither final_image_url nor image_urls)');
}

// post_id: derive from session/timestamp. Prefer an existing session_id if present (set by Recuperar sesion Supabase).
const postId = data.session_id || ('propulsar_' + Date.now());

return [{
  json: {
    // Pass ALL upstream fields through so downstream nodes (Sheets Log, future Meta publish)
    // still have access to topic, type, angle, instagram/facebook text, etc.
    ...data,
    // Plus the sub-workflow input fields:
    image_urls: imageUrls,
    post_id: postId,
    approval_number: data.approval_number
  }
}];

const carousel = $('🔧 Parsear prompts carrusel').first().json;
const loopItems = $input.all();

// IMG-02: Normalize and validate all image URLs
const imageUrls = loopItems.map(item => {
  const url = item.json.data?.[0]?.url || null;
  if (url && typeof url === 'string' && url.startsWith('https://')) {
    return url; // Keep full URL with auth params (exp, sig)
  }
  return null;
}).filter(Boolean);

if (imageUrls.length !== carousel.num_images) {
  throw new Error('Se generaron ' + imageUrls.length + ' imagenes, se esperaban ' + carousel.num_images + '. Faltan slides.');
}

return [{
  json: {
    instagram:       carousel.instagram,
    facebook:        carousel.facebook,
    topic:           carousel.topic,
    type:            carousel.type,
    angle:           carousel.angle || null,
    platforms:       carousel.platforms,
    image_model:     'ideogram',
    approval_number: carousel.approval_number,
    timestamp:       carousel.timestamp,
    publish_at:      carousel.publish_at || 'now',
    format:          'carousel',
    num_images:      carousel.num_images,
    image_urls:      imageUrls,
    final_image_url: imageUrls[0] || null,
  }
}];

const data = $input.first().json;
const urls = data.image_urls;

return urls.map((url, idx) => ({
  json: {
    current_image_url: url,
    slide_index:       idx + 1,
    num_images:        data.num_images,
    approval_number:   data.approval_number,
    _carousel_data:    data,
  }
}));

const data = $('🔗 Merge Rehost Output').first().json;
const blobUrls = data.blob_urls || [];
if (blobUrls.length === 0) {
  throw new Error('IG Carousel Explode: no blob_urls found in Merge Rehost Output');
}
if (blobUrls.length > 10) {
  throw new Error('IG Carousel Explode: carousel exceeds 10-slide Meta limit (' + blobUrls.length + ' slides)');
}
return blobUrls.map((entry, i) => ({
  json: {
    slide_index: entry.index || (i + 1),
    blob_url: entry.url,
    num_images: blobUrls.length,
  }
}));

const items = $input.all();
const session = $('🔗 Merge Rehost Output').first().json;
const childIds = items.map(it => it.json.id).filter(Boolean);
if (childIds.length !== session.blob_urls.length) {
  throw new Error('IG Carousel: expected ' + session.blob_urls.length + ' child containers, got ' + childIds.length);
}
return [{
  json: {
    topic: session.topic,
    type: session.type,
    angle: session.angle || null,
    platforms: session.platforms,
    image_model: session.image_model,
    instagram_caption: session.instagram_caption,
    facebook_caption: session.facebook_caption,
    blob_urls: session.blob_urls,
    approval_number: session.approval_number,
    format: session.format,
    num_images: session.blob_urls.length,
    child_ids: childIds,
    children_csv: childIds.join(','),
  }
}];

const session = $('🔗 Merge Rehost Output').first().json;
const blobUrls = session.blob_urls || [];
return blobUrls.map((entry, i) => ({
  json: {
    slide_index: entry.index || (i + 1),
    blob_url: entry.url,
  }
}));

const items = $input.all();
const session = $('🔗 Merge Rehost Output').first().json;
const photoIds = items.map(it => it.json.id).filter(Boolean);
if (photoIds.length !== session.blob_urls.length) {
  throw new Error('FB Carousel: expected ' + session.blob_urls.length + ' unpublished photos, got ' + photoIds.length);
}
return [{
  json: {
    photo_ids: photoIds,
    facebook_caption: session.facebook_caption || session.instagram_caption || '',
    instagram_permalink: $('🔗 IG: Get Carousel Permalink').first().json.permalink,
    approval_number: session.approval_number,
    topic: session.topic,
    type: session.type,
    angle: session.angle || null,
    image_model: session.image_model,
    num_images: session.blob_urls.length,
    format: 'carousel',
    blob_urls: session.blob_urls,
    instagram_caption: session.instagram_caption,
  }
}];

const data = $input.first().json;
const photoIds = data.photo_ids;
if (!Array.isArray(photoIds) || photoIds.length === 0) {
  throw new Error('FB Build attached_media: no photo_ids found');
}
const attachedMedia = photoIds.map(id => ({ media_fbid: id }));
return [{
  json: {
    ...data,
    attached_media: attachedMedia,
  }
}];

const data = $input.first().json;
const pub = data.publish_at;

let scheduled = false;
let wait_seconds = 0;

if (pub && pub !== 'now') {
  const diffMs = new Date(pub).getTime() - Date.now();
  if (diffMs > 65000 && diffMs <= 86400000) {
    scheduled = true;
    wait_seconds = Math.round(diffMs / 1000);
  }
  // Past time or > 24h: route to immediate (scheduled stays false)
}

return [{ json: { ...data, scheduled: String(scheduled), wait_seconds } }];
